const express = require('express');
const jwt = require('jsonwebtoken');

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';
const ALLOWED_ALGORITHMS = ['HS256'];
const ISSUER = process.env.JWT_ISSUER || 'my-api';
const AUDIENCE = process.env.JWT_AUDIENCE || 'my-app';

function verifyJWT(options = {}) {
  const {
    secret = JWT_SECRET,
    algorithms = ALLOWED_ALGORITHMS,
    issuer = ISSUER,
    audience = AUDIENCE,
    credentialsRequired = true,
  } = options;

  return (req, res, next) => {
    const authHeader = req.headers.authorization;

    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      if (credentialsRequired) {
        return res.status(401).json({
          error: 'Authentication required',
          message: 'Missing or malformed Authorization header. Expected: Bearer <token>',
        });
      }
      req.user = null;
      return next();
    }

    const token = authHeader.split(' ')[1];

    if (!token) {
      return res.status(401).json({
        error: 'Authentication required',
        message: 'Token not provided',
      });
    }

    try {
      const decoded = jwt.verify(token, secret, {
        algorithms: algorithms,
        issuer: issuer,
        audience: audience,
        complete: false,
        clockTolerance: 5,
      });

      if (!decoded.sub) {
        return res.status(401).json({
          error: 'Invalid token',
          message: 'Token missing required "sub" claim',
        });
      }

      if (!decoded.exp) {
        return res.status(401).json({
          error: 'Invalid token',
          message: 'Token missing required "exp" claim',
        });
      }

      if (!decoded.iat) {
        return res.status(401).json({
          error: 'Invalid token',
          message: 'Token missing required "iat" claim',
        });
      }

      req.user = {
        id: decoded.sub,
        email: decoded.email || null,
        name: decoded.name || null,
        roles: decoded.roles || [],
        issuedAt: new Date(decoded.iat * 1000),
        expiresAt: new Date(decoded.exp * 1000),
        claims: decoded,
      };

      next();
    } catch (err) {
      if (err.name === 'TokenExpiredError') {
        return res.status(401).json({
          error: 'Token expired',
          message: 'Your token has expired. Please re-authenticate.',
          expiredAt: err.expiredAt,
        });
      }

      if (err.name === 'JsonWebTokenError') {
        return res.status(401).json({
          error: 'Invalid token',
          message: `Token verification failed: ${err.message}`,
        });
      }

      if (err.name === 'NotBeforeError') {
        return res.status(401).json({
          error: 'Token not active',
          message: 'Token is not yet valid',
          notBefore: err.date,
        });
      }

      return res.status(500).json({
        error: 'Authentication error',
        message: 'An unexpected error occurred during authentication',
      });
    }
  };
}

function requireRoles(...roles) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({
        error: 'Authentication required',
        message: 'You must be authenticated to access this resource',
      });
    }

    const userRoles = req.user.roles || [];
    const hasRequiredRole = roles.some((role) => userRoles.includes(role));

    if (!hasRequiredRole) {
      return res.status(403).json({
        error: 'Forbidden',
        message: `Insufficient permissions. Required roles: ${roles.join(', ')}`,
      });
    }

    next();
  };
}

function generateToken(payload, options = {}) {
  const {
    secret = JWT_SECRET,
    expiresIn = '1h',
    issuer = ISSUER,
    audience = AUDIENCE,
  } = options;

  if (!payload.sub) {
    throw new Error('Payload must include a "sub" (subject) claim');
  }

  return jwt.sign(payload, secret, {
    algorithm: ALLOWED_ALGORITHMS[0],
    expiresIn: expiresIn,
    issuer: issuer,
    audience: audience,
  });
}

