const app = express();
app.use(express.json());

// Public route - no auth needed
app.get('/api/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Demo login route - generates a token
app.post('/api/login', (req, res) => {
  const { email, password } = req.body;

  // Simulated user lookup (replace with real DB lookup in production)
  if (email === 'user@example.com' && password === 'password123') {
    const token = generateToken({
      sub: 'user-123',
      email: 'user@example.com',
      name: 'Demo User',
      roles: ['user'],
    });

    return res.json({ token, tokenType: 'Bearer' });
  }

  if (email === 'admin@example.com' && password === 'admin123') {
    const token = generateToken({
      sub: 'admin-456',
      email: 'admin@example.com',
      name: 'Admin User',
      roles: ['user', 'admin'],
    });

    return res.json({ token, tokenType: 'Bearer' });
  }

  res.status(401).json({ error: 'Invalid credentials' });
});

// Protected route - requires valid JWT
app.get('/api/profile', verifyJWT(), (req, res) => {
  res.json({
    message: 'Authenticated successfully',
    user: req.user,
  });
});

// Protected route with role check
app.get('/api/admin/dashboard', verifyJWT(), requireRoles('admin'), (req, res) => {
  res.json({
    message: 'Welcome to the admin dashboard',
    user: req.user,
  });
});

// Optional auth route - works with or without token
app.get('/api/content', verifyJWT({ credentialsRequired: false }), (req, res) => {
  if (req.user) {
    res.json({
      message: 'Personalized content for authenticated user',
      user: req.user,
    });
  } else {
    res.json({
      message: 'Public content for anonymous user',
    });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Health check: http://localhost:${PORT}/api/health`);
  console.log(`Login: POST http://localhost:${PORT}/api/login`);
  console.log(`Profile: GET http://localhost:${PORT}/api/profile`);
  console.log(`Admin: GET http://localhost:${PORT}/api/admin/dashboard`);
});

module.exports = { verifyJWT, requireRoles, generateToken, app };